from typing import List

class Solution:
    def execute_command(self, command: List[List[str]]) -> str:
        # 定义双向链表节点
        class Node:
            def __init__(self, val: str):
                self.val = val
                self.prev = None
                self.next = None

        # 创建虚拟头节点，表示初始状态
        head = Node("")
        cur = head

        for cmd in command:
            # 兼容 [[]] 这种空命令样例
            if not cmd:
                continue

            op = cmd[0]

            if op == "execute":
                # 执行新命令，清除当前之后的 redo 历史
                desc = cmd[1]
                cur.next = None

                # 新建节点保存操作描述
                node = Node(desc)
                node.prev = cur
                cur.next = node
                cur = node

            elif op == "undo":
                # 回退至上一个状态
                if cur == head:
                    return "undo failed"
                cur = cur.prev

            else:
                # redo 操作
                if cur.next is None:
                    return "redo failed"
                cur = cur.next

        # 返回当前操作描述
        return cur.val
```

```java
import java.util.*;

public class Solution {
    public String execute_command(String[][] command) {
        List<String> history = new ArrayList<>();
        int cur = -1; // 当前索引位置，-1 表示初始状态

        for (String[] cmd : command) {
            // 兼容空命令
            if (cmd.length == 0) {
                continue;
            }

            String op = cmd[0];

            if (op.equals("execute")) {
                // execute 命令才有第二个元素
                if (cmd.length < 2) {
                    continue;
                }

                // 清空当前状态之后的 redo 历史
                while (history.size() > cur + 1) {
                    history.remove(history.size() - 1);
                }

                // 新建操作节点并存入历史
                history.add(cmd[1]);
                cur++;
            } else if (op.equals("undo")) {
                // 回退操作
                if (cur == -1) {
                    return "undo failed";
                }
                cur--;
            } else if (op.equals("redo")) {
                // 重做操作
                if (cur + 1 >= history.size()) {
                    return "redo failed";
                }
                cur++;
            }
        }

        // 返回当前操作状态描述
        if (cur == -1) {
            return "";
        }
        return history.get(cur);
    }
}
