#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string execute_command(vector<vector<string>>& command) {
        vector<string> history;
        int cur = -1; // 当前索引位置，-1 表示初始状态

        for (auto& cmd : command) {
            // 兼容空命令
            if (cmd.empty()) continue;

            string op = cmd[0];

            if (op == "execute") {
                // execute 命令才有第二个元素
                if (cmd.size() < 2) continue;

                // 清空当前状态之后的 redo 历史
                while ((int)history.size() > cur + 1) {
                    history.pop_back();
                }

                // 新建操作节点并存入历史
                history.push_back(cmd[1]);
                cur++;
            } else if (op == "undo") {
                // 回退操作
                if (cur == -1) {
                    return "undo failed";
                }
                cur--;
            } else if (op == "redo") {
                // 重做操作
                if (cur + 1 >= (int)history.size()) {
                    return "redo failed";
                }
                cur++;
            }
        }

        // 返回当前操作状态描述
        if (cur == -1) return "";
        return history[cur];
    }
};
